// Block body
const greet = name => {
  const message = "Hello " + name;
  return message;
};

// Default parameters
function greet(name = "Guest") {
  return "Hello " + name;
}

// Rest parameters
function sum(...numbers) {
  return numbers.reduce((a, b) => a + b);
}

const global = "I am everywhere";

function outer() {
  const outerVar = "I am in outer";

  function inner() {
    const innerVar = "I am in inner";
    console.log(global);    // ✓ accessible
    console.log(outerVar);  // ✓ accessible (closure!)
    console.log(innerVar);  // ✓ accessible
  }
}

// Closure example
function createCounter() {
  let count = 0;  // Private variable

  return {
    increment: () => ++count,
    decrement: () => --count,
    getCount: () => count
  };
}

const counter = createCounter();
counter.increment(); // 1
counter.increment(); // 2
console.log(counter.getCount()); // 2

// var is hoisted (initialized as undefined)
console.log(x); // undefined
var x = 5;

// let/const are hoisted but not initialized (TDZ)
console.log(y); // ReferenceError!
let y = 5;

// Functions are fully hoisted
greet(); // Works!
function greet() { return "Hi"; }

// 1. Default: window (strict: undefined)
function greet() { console.log(this); }
greet(); // window

// 2. Implicit: object method
const user = {
  name: "Mirlind",
  greet() { console.log(this.name); }
};
user.greet(); // "Mirlind"

// 3. Explicit: call, apply, bind
greet.call(user); // this = user

